SELECT leaf_1.year, leaf_1.round, leaf_1.series, leaf_1.tmidwinner, leaf_1.goalswinner, leaf_1.coachid, leaf_1.award FROM (SELECT sp.year, sp.round, sp.series, sp.tmidwinner, sp.goalswinner, c.coachid, a.award FROM seriespost AS sp JOIN teams AS t ON sp.tmidwinner = t.tmid JOIN coaches AS c ON t.tmid = c.tmid JOIN awardscoaches AS a ON c.coachid = a.coachid WHERE (sp.round = 'QF') AND (a.award = 'First Team All-Star')) AS leaf_1
